exercices.code_script:
disp('Résolution d''une équation de 2nd degré de la forme ax2 + bx + c = 0');
a = input('a = ');
b = input('b = ');
c = input('c = ');
d = delta(a, b, c);
if d < 0
  disp('pas de solution réelle');
elseif d > 0
  disp('deux racines distinctes');
  x1 = (-b - sqrt(d)) / (2*a);
  x2 = (-b + sqrt(d)) / (2*a);
  disp(['x1 = ', num2str(x1)]);
  disp(['x2 = ', num2str(x2)]);
else
  disp('une racine double');
  x1 = -b / (2*a);
  disp(['x1 = x2 = ', num2str(x1)]);
end

exercices.code_function:
function [d] = delta(a, b, c)
  d = b^2 - 4*a*c;
end

